('u1-fc-4', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Why computers use binary","definition":"The CPU is built from logic gates with two states (on/off), so all data must be converted to binary to be processed and stored in registers."}'::jsonb, true),
('u1-fc-5', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Why hexadecimal is used","definition":"It is a shorter, easier representation of binary for humans to read and write, e.g. MAC addresses, colour codes, memory addresses and error codes."}'::jsonb, true),
('u1-fc-6', 'flashcard', array['match', 'memory']::text[], 2, '{"term":"Overflow","definition":"An error that occurs when a calculation produces a value larger than the number of bits can hold (e.g. greater than 255 in an 8-bit register)."}'::jsonb, true),
('u1-fc-7', 'flashcard', array['match', 'memory']::text[], 2, '{"term":"Logical left shift","definition":"Moves all bits left; zeros fill in from the right; bits lost off the left end. Each shift of one place multiplies the value by 2."}'::jsonb, true),
('u1-fc-8', 'flashcard', array['match', 'memory']::text[], 2, '{"term":"Logical right shift","definition":"Moves all bits right; zeros fill in from the left; bits lost off the right end. Each shift of one place divides the value by 2."}'::jsonb, true),
('u1-fc-9', 'flashcard', array['match', 'memory']::text[], 3, '{"term":"Two''s complement","definition":"A method of representing positive and negative 8-bit binary integers, where the most significant bit has a negative place value."}'::jsonb, true),
