('u2-fc-1', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Packet","definition":"A small unit that data is broken down into so it can be transmitted across a network."}'::jsonb, true),
('u2-fc-2', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Packet header","definition":"The part of a packet containing the destination address, packet number and originator''s (sender''s) address."}'::jsonb, true),
('u2-fc-3', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Payload","definition":"The actual data being carried inside a packet."}'::jsonb, true),
('u2-fc-4', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Trailer","definition":"The part of a packet that marks the end of the packet and can contain error-checking data."}'::jsonb, true),
('u2-fc-5', 'flashcard', array['match', 'memory']::text[], 2, '{"term":"Packet switching","definition":"Data is split into packets, each can take a different route controlled by routers, and packets are reordered at the destination once the last one arrives."}'::jsonb, true),
('u2-fc-6', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Serial transmission","definition":"Bits are sent one after another down a single wire/channel."}'::jsonb, true),
('u2-fc-7', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Parallel transmission","definition":"Several bits are sent at the same time down multiple wires/channels."}'::jsonb, true),
('u2-fc-8', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Simplex","definition":"Data is transmitted in one direction only."}'::jsonb, true),
('u2-fc-9', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Half-duplex","definition":"Data is transmitted in both directions, but only one direction at a time."}'::jsonb, true),
('u2-fc-10', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Full-duplex","definition":"Data is transmitted in both directions at the same time."}'::jsonb, true),
('u2-fc-11', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"USB","definition":"Universal Serial Bus; a common serial interface used to connect devices and transmit data."}'::jsonb, true),
('u2-fc-12', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Why errors occur","definition":"Interference during transmission can cause data loss, data gain or data change."}'::jsonb, true),
('u2-fc-13', 'flashcard', array['match', 'memory']::text[], 2, '{"term":"Parity check","definition":"An extra parity bit is added so the number of 1s is odd or even; if the parity does not match on arrival, an error is detected."}'::jsonb, true),
('u2-fc-14', 'flashcard', array['match', 'memory']::text[], 3, '{"term":"Parity block check","definition":"Parity bits are calculated across both rows and columns of a block of data so the exact position of an error can be found."}'::jsonb, true),
('u2-fc-15', 'flashcard', array['match', 'memory']::text[], 2, '{"term":"Checksum","definition":"A value calculated from the data is sent with it; the receiver recalculates and compares to check for errors."}'::jsonb, true),
