('u3-fc-1', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"CPU","definition":"The Central Processing Unit; processes the instructions and data that are input so a result can be output."}'::jsonb, true),
('u3-fc-2', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Microprocessor","definition":"A type of integrated circuit on a single chip."}'::jsonb, true),
('u3-fc-3', 'flashcard', array['match', 'memory']::text[], 2, '{"term":"Von Neumann architecture","definition":"An architecture where instructions and data are stored together in the same memory and processed by a single CPU."}'::jsonb, true),
('u3-fc-4', 'flashcard', array['match', 'memory']::text[], 1, '{"term":"Arithmetic Logic Unit (ALU)","definition":"The CPU component that carries out calculations and logical operations."}'::jsonb, true),
